### Complete User Authentication Example
```python
import bcrypt
import re
from typing import Optional

class UserAuth:
    MIN_LENGTH = 12
    REQUIRE_SPECIAL = True

    @staticmethod
    def validate_password(password: str) -> tuple[bool, str]:
        """Validate password strength."""
        if len(password) < UserAuth.MIN_LENGTH:
            return False, f'Password must be at least {UserAuth.MIN_LENGTH} characters'

        if not re.search(r'[A-Z]', password):
            return False, 'Password must contain uppercase letter'

        if not re.search(r'[a-z]', password):
            return False, 'Password must contain lowercase letter'

        if not re.search(r'\d', password):
            return False, 'Password must contain digit'

        if UserAuth.REQUIRE_SPECIAL and not re.search(r'[!@#$%^&*]', password):
            return False, 'Password must contain special character'

        return True, 'Valid'

    @staticmethod
    def hash_password(password: str) -> str:
        return bcrypt.hashpw(password.encode(), bcrypt.gensalt()).decode()

    @staticmethod
    def verify(password: str, hashed: str) -> bool:
        return bcrypt.checkpw(password.encode(), hashed.encode())

# Usage
is_valid, msg = UserAuth.validate_password('MyStr0ng!Pass')
if is_valid:
    hashed = UserAuth.hash_password('MyStr0ng!Pass')
